WITH t1 AS ( SELECT substring(address from 4 for 3) AS x_axis, diaper AS data FROM public.test1), t2 AS ( SELECT "行政區" AS x_axis, "尿布臺設置數量" AS data FROM public.test2) SELECT x_axis, SUM(data) AS data FROM ( SELECT * FROM t1 UNION ALL SELECT * FROM t2) combined GROUP BY x_axis ORDER BY ARRAY_POSITION( ARRAY[ '北投區', '士林區', '內湖區', '南港區', '松山區', '信義區', '中山區', '大同區', '中正區', '萬華區', '大安區', '文山區', '新莊區', '淡水區', '汐止區', '板橋區', '三重區', '樹林區', '土城區', '蘆洲區', '中和區', '永和區', '新店區', '鶯歌區', '三峽區', '瑞芳區', '五股區', '泰山區', '林口區', '深坑區', '石碇區', '坪林區', '三芝區', '石門區', '八里區', '平溪區', '雙溪區', '貢寮區', '金山區', '萬里區', '烏來區' ], x_axis) ASC;